const dashboard = $('Fetch Dashboard').first().json;
const draftItems = $('Fetch Drafts').all().map(i => i.json);
const allDrafts = draftItems.length > 0 && draftItems[0].title ? draftItems : [];
const scheduleItems = $('Fetch Schedule').all().map(i => i.json);
const schedule = scheduleItems.length > 0 && scheduleItems[0].title ? scheduleItems : [];
const gapItems = $('Fetch Market Gaps').all().map(i => i.json);
const gaps = gapItems.length > 0 && gapItems[0].description ? gapItems : [];
const repoItems = $('Fetch GitHub').all().map(i => i.json);
// Deduplicate repos by name (n8n splits arrays into items)
const repoMap = {};
repoItems.forEach(r => { if (r.name) repoMap[r.name] = r; });
const repos = Object.values(repoMap);

const tasks = (dashboard.tasks || []).sort((a, b) => b.priority_score - a.priority_score);
const top3 = tasks.slice(0, 3);
const goals = dashboard.goals_week || [];
const goalsMonth = dashboard.goals_month || [];
const suggestions = (dashboard.suggestions || []).slice(0, 3);
const briefing = (dashboard.briefing || []).slice(0, 5);
const projects = dashboard.projects || [];
const blockers = projects.filter(p => p.blockers);
const totalMin = tasks.reduce((s, t) => s + (t.estimated_minutes || 0), 0);
const focusTime = totalMin >= 60 ? (totalMin / 60).toFixed(1) + 'h' : totalMin + 'm';

// --- Today's Game Plan ---
const gamePlan = top3.map((t, i) =>
  '<tr><td style="padding:12px 8px;border-bottom:1px solid #1E1E2D;color:#A855F7;font-size:20px;font-weight:bold;vertical-align:top;width:30px">' + (i+1) + '</td>' +
  '<td style="padding:12px 8px;border-bottom:1px solid #1E1E2D"><div style="color:#E4E4E7;font-weight:600;font-size:15px">' + t.title + '</div>' +
  '<div style="color:#9494AD;font-size:13px;margin-top:4px">' + (t.why || '') + '</div>' +
  '<div style="color:#6A6A80;font-size:12px;margin-top:6px">' + (t.project_tag || '') + ' &middot; ' + (t.estimated_minutes || 30) + ' min</div></td></tr>'
).join('');

// --- All Tasks ---
const taskRows = tasks.map(t =>
  '<tr><td style="padding:8px;border-bottom:1px solid #1E1E2D;color:#E4E4E7">' + t.title + '</td>' +
  '<td style="padding:8px;text-align:center;border-bottom:1px solid #1E1E2D;color:#A855F7;font-weight:bold">' + t.priority_score.toFixed(1) + '</td>' +
  '<td style="padding:8px;text-align:center;border-bottom:1px solid #1E1E2D;color:#9494AD">' + (t.estimated_minutes || 30) + 'm</td>' +
  '<td style="padding:8px;text-align:center;border-bottom:1px solid #1E1E2D;color:#6A6A80">' + (t.project_tag || '') + '</td></tr>'
).join('');

// --- Content Drafts (FULL content) ---
const draftCards = allDrafts.map(d => {
  const body = (d.body || '').replace(/\n/g, '<br>');
  const scoreText = d.hook_score ? Math.round(d.hook_score * 100) + '%' : 'N/A';
  return '<div style="background:#111118;border-radius:12px;padding:20px;margin-bottom:16px;border-left:3px solid #A855F7">' +
    '<div style="margin-bottom:12px"><span style="color:#E4E4E7;font-weight:700;font-size:16px">' + d.title + '</span>' +
    '<span style="color:#A855F7;font-size:11px;background:#A855F720;padding:2px 8px;border-radius:12px;margin-left:8px">' + d.platform + '</span>' +
    '<span style="color:#6A6A80;font-size:11px;margin-left:8px">' + (d.content_type || '') + ' &middot; Hook: ' + scoreText + '</span></div>' +
    (d.hook ? '<div style="color:#C084FC;font-style:italic;font-size:14px;margin-bottom:12px;padding:10px;background:#A855F708;border-radius:8px">&ldquo;' + d.hook + '&rdquo;</div>' : '') +
    '<div style="color:#9494AD;font-size:13px;line-height:1.6">' + body + '</div>' +
    (d.hashtags ? '<div style="color:#6A6A80;font-size:11px;margin-top:10px">' + d.hashtags + '</div>' : '') +
    (d.cta ? '<div style="color:#06B6D4;font-size:12px;margin-top:8px;font-weight:600">CTA: ' + d.cta + '</div>' : '') +
  '</div>';
}).join('');

// --- Schedule ---
const scheduleRows = schedule.slice(0, 10).map(s => {
  const date = s.scheduled_at ? new Date(s.scheduled_at).toLocaleDateString('en-US', {weekday: 'short', month: 'short', day: 'numeric'}) : '';
  return '<tr><td style="padding:6px 8px;border-bottom:1px solid #1E1E2D;color:#9494AD;font-size:12px;width:100px">' + date + '</td>' +
    '<td style="padding:6px 8px;border-bottom:1px solid #1E1E2D;color:#E4E4E7;font-size:13px">' + s.title + '</td>' +
    '<td style="padding:6px 8px;border-bottom:1px solid #1E1E2D;color:#A855F7;font-size:11px;text-align:center">' + (s.platform || '') + '</td>' +
    '<td style="padding:6px 8px;border-bottom:1px solid #1E1E2D;font-size:11px;text-align:center;color:' + (s.status === 'scheduled' ? '#F59E0B' : '#10B981') + '">' + (s.status || '') + '</td></tr>';
}).join('');

// --- Market Gaps ---
const gapCards = gaps.slice(0, 5).map(g => {
  const score = g.opportunity_score ? Math.round(g.opportunity_score * 100) + '%' : '';
  return '<div style="background:#111118;border-radius:8px;padding:12px;margin-bottom:8px;border-left:3px solid #EC4899">' +
    '<div style="color:#E4E4E7;font-size:13px;font-weight:600">' + g.description + '</div>' +
    (g.suggested_action ? '<div style="color:#9494AD;font-size:12px;margin-top:6px">Action: ' + g.suggested_action + '</div>' : '') +
    '<div style="color:#6A6A80;font-size:11px;margin-top:4px">' + (g.source || '') + (score ? ' &middot; Opportunity: ' + score : '') + '</div>' +
  '</div>';
}).join('');

// --- GitHub Repos ---
const repoRows = repos.map(r => {
  const daysAgo = r.last_commit_at ? Math.round((Date.now() - new Date(r.last_commit_at).getTime()) / 86400000) : '?';
  return '<tr><td style="padding:6px 8px;border-bottom:1px solid #1E1E2D;color:#E4E4E7;font-size:13px;font-weight:600">' + r.name + '</td>' +
    '<td style="padding:6px 8px;border-bottom:1px solid #1E1E2D;color:#9494AD;font-size:12px">' + (r.last_commit_message || '').slice(0, 40) + '</td>' +
    '<td style="padding:6px 8px;border-bottom:1px solid #1E1E2D;color:#6A6A80;font-size:11px;text-align:center">' + daysAgo + 'd ago</td>' +
    '<td style="padding:6px 8px;border-bottom:1px solid #1E1E2D;color:#F59E0B;font-size:11px;text-align:center">' + (r.stars || 0) + '</td></tr>';
}).join('');

// --- Goals ---
const goalRows = goals.map(g =>
  '<div style="display:flex;justify-content:space-between;padding:6px 0;border-bottom:1px solid #1E1E2D">' +
  '<span style="color:#E4E4E7;font-size:13px">' + g.title + '</span>' +
  '<span style="color:' + (g.progress >= 0.5 ? '#10B981' : g.progress > 0 ? '#F59E0B' : '#6A6A80') + ';font-weight:bold;font-size:13px">' + Math.round(g.progress * 100) + '%</span></div>'
).join('');
const monthGoalRows = goalsMonth.map(g =>
  '<div style="display:flex;justify-content:space-between;padding:6px 0;border-bottom:1px solid #1E1E2D">' +
  '<span style="color:#E4E4E7;font-size:13px">' + g.title + '</span>' +
  '<span style="color:' + (g.progress >= 0.5 ? '#10B981' : g.progress > 0 ? '#F59E0B' : '#6A6A80') + ';font-weight:bold;font-size:13px">' + Math.round(g.progress * 100) + '%</span></div>'
).join('');

// --- Blockers ---
const blockerRows = blockers.map(p =>
  '<div style="background:#F59E0B15;border-left:3px solid #F59E0B;padding:10px 12px;border-radius:8px;margin-bottom:8px">' +
  '<span style="color:#F59E0B;font-weight:600;font-size:13px">' + p.name + ':</span> ' +
  '<span style="color:#9494AD;font-size:13px">' + p.blockers + '</span></div>'
).join('');

// --- AI Suggestions ---
const suggestionRows = suggestions.map(s =>
  '<div style="background:#A855F710;border-left:3px solid #A855F7;padding:10px 12px;border-radius:8px;margin-bottom:8px">' +
  '<span style="color:#E4E4E7;font-size:13px">' + s.body + '</span></div>'
).join('');

// --- News ---
const newsRows = briefing.map(b =>
  '<div style="padding:8px 0;border-bottom:1px solid #1E1E2D">' +
  '<div style="color:#E4E4E7;font-size:13px;font-weight:600">' + b.headline + '</div>' +
  (b.summary ? '<div style="color:#9494AD;font-size:12px;margin-top:2px">' + b.summary + '</div>' : '') +
  (b.suggested_action ? '<div style="color:#06B6D4;font-size:11px;margin-top:4px">Action: ' + b.suggested_action + '</div>' : '') +
  '</div>'
).join('');

// --- BUILD EMAIL ---
const emailHtml = '<div style="font-family:-apple-system,BlinkMacSystemFont,sans-serif;max-width:700px;margin:0 auto;background:#0A0A0B;color:#E4E4E7;padding:32px;border-radius:16px">' +

'<div style="text-align:center;margin-bottom:32px">' +
'<h1 style="color:#A855F7;font-size:28px;margin:0">Operator Briefing</h1>' +
'<p style="color:#6A6A80;font-size:14px;margin:8px 0 0">' + new Date().toLocaleDateString('en-US', {weekday: 'long', month: 'long', day: 'numeric', year: 'numeric'}) + '</p>' +
'<p style="color:#9494AD;font-size:13px;margin:4px 0 0">' + tasks.length + ' tasks &middot; ' + focusTime + ' focus time &middot; ' + allDrafts.length + ' drafts &middot; ' + schedule.length + ' scheduled &middot; ' + repos.length + ' repos</p></div>' +

// Game Plan
'<div style="background:#111118;border-radius:12px;padding:20px;margin-bottom:24px">' +
'<h2 style="color:#E4E4E7;font-size:18px;margin:0 0 16px;border-bottom:1px solid #222;padding-bottom:8px">Today\'s Game Plan</h2>' +
(top3.length > 0 ? '<table style="width:100%;border-collapse:collapse">' + gamePlan + '</table>' : '<p style="color:#6A6A80">Hit AI Generate to get your priorities.</p>') + '</div>' +

// Blockers
(blockers.length > 0 ? '<div style="margin-bottom:24px"><h2 style="color:#F59E0B;font-size:16px;margin:0 0 12px">Blockers (' + blockers.length + ')</h2>' + blockerRows + '</div>' : '') +

// All Tasks
'<h2 style="color:#E4E4E7;font-size:16px;border-bottom:1px solid #222;padding-bottom:8px;margin-bottom:12px">All Priority Tasks (' + tasks.length + ')</h2>' +
'<table style="width:100%;border-collapse:collapse;margin-bottom:24px">' +
'<tr style="color:#6A6A80;font-size:11px;text-transform:uppercase"><th style="text-align:left;padding:8px">Task</th><th style="padding:8px;width:50px">Score</th><th style="padding:8px;width:50px">Time</th><th style="padding:8px;width:80px">Project</th></tr>' +
taskRows + '</table>' +

// Content Drafts (full)
'<h2 style="color:#E4E4E7;font-size:16px;border-bottom:1px solid #222;padding-bottom:8px;margin-bottom:12px">Content Drafts (' + allDrafts.length + ')</h2>' +
(draftCards || '<p style="color:#6A6A80">No pending drafts.</p>') +
'<div style="margin-bottom:24px"></div>' +

// Schedule
(schedule.length > 0 ? '<h2 style="color:#E4E4E7;font-size:16px;border-bottom:1px solid #222;padding-bottom:8px;margin-bottom:12px">Schedule (' + schedule.length + ' items)</h2>' +
'<table style="width:100%;border-collapse:collapse;margin-bottom:24px">' +
'<tr style="color:#6A6A80;font-size:11px;text-transform:uppercase"><th style="text-align:left;padding:6px 8px">Date</th><th style="text-align:left;padding:6px 8px">Title</th><th style="padding:6px 8px">Platform</th><th style="padding:6px 8px">Status</th></tr>' +
scheduleRows + '</table>' : '') +

// Market Gaps
(gaps.length > 0 ? '<h2 style="color:#E4E4E7;font-size:16px;border-bottom:1px solid #222;padding-bottom:8px;margin-bottom:12px">Market Intelligence (' + gaps.length + ' gaps)</h2>' +
gapCards + '<div style="margin-bottom:24px"></div>' : '') +

// GitHub
(repos.length > 0 ? '<h2 style="color:#E4E4E7;font-size:16px;border-bottom:1px solid #222;padding-bottom:8px;margin-bottom:12px">GitHub Progress (' + repos.length + ' repos)</h2>' +
'<table style="width:100%;border-collapse:collapse;margin-bottom:24px">' +
'<tr style="color:#6A6A80;font-size:11px;text-transform:uppercase"><th style="text-align:left;padding:6px 8px">Repo</th><th style="text-align:left;padding:6px 8px">Last Commit</th><th style="padding:6px 8px">When</th><th style="padding:6px 8px">Stars</th></tr>' +
repoRows + '</table>' : '') +

// Goals
'<div style="margin-bottom:24px">' +
'<h2 style="color:#E4E4E7;font-size:16px;border-bottom:1px solid #222;padding-bottom:8px;margin-bottom:8px">Weekly Goals</h2>' +
(goalRows || '<p style="color:#6A6A80;font-size:13px">No weekly goals.</p>') +
'<h2 style="color:#E4E4E7;font-size:16px;border-bottom:1px solid #222;padding-bottom:8px;margin-bottom:8px;margin-top:16px">Monthly Goals</h2>' +
(monthGoalRows || '<p style="color:#6A6A80;font-size:13px">No monthly goals.</p>') + '</div>' +

// Suggestions
(suggestions.length > 0 ? '<h2 style="color:#E4E4E7;font-size:16px;border-bottom:1px solid #222;padding-bottom:8px;margin-bottom:12px">AI Suggestions</h2>' + suggestionRows + '<div style="margin-bottom:24px"></div>' : '') +

// News
(briefing.length > 0 ? '<h2 style="color:#E4E4E7;font-size:16px;border-bottom:1px solid #222;padding-bottom:8px;margin-bottom:12px">Industry News</h2>' + newsRows + '<div style="margin-bottom:24px"></div>' : '') +

// Footer
'<div style="text-align:center;padding-top:16px;border-top:1px solid #1E1E2D">' +
'<p style="color:#6A6A80;font-size:11px">Generated by Operator Dashboard AI</p></div>' +

'</div>';

// --- SMS text (short version for Twilio) ---
const smsText = 'Daily Focus — ' + new Date().toLocaleDateString('en-US', {weekday: 'short', month: 'short', day: 'numeric'}) + '\n\n' +
  top3.map((t, i) => (i+1) + '. ' + t.title + ' (' + (t.estimated_minutes || 30) + 'm)').join('\n') +
  '\n\n' + tasks.length + ' tasks · ' + focusTime + ' focus time' +
  (blockers.length > 0 ? '\n⚠ ' + blockers.length + ' blocker(s)' : '') +
  '\nReply: done 1, add [task], tasks';

return [{ json: { emailHtml, emailSubject: 'Operator Briefing — ' + new Date().toLocaleDateString('en-US', {month: 'short', day: 'numeric'}), smsText, taskCount: tasks.length } }];
